const amqp = require('amqplib');
const mysql = require('mysql');

// RabbitMQ connection details
const rabbitmqUrl = 'amqp://localhost';
const queueName = 'event_queue';

// MySQL database connection details
const dbConfig = {
  host: 'localhost',
  user: 'your_user',
  password: 'your_password',
  database: 'your_database'
};

let connection;
let channel;

async function connectToRabbitMQ() {
  try {
    connection = await amqp.connect(rabbitmqUrl);
    channel = await connection.createChannel();
    await channel.assertQueue(queueName, { durable: false });
    console.log('Connected to RabbitMQ and asserted queue');
  } catch (error) {
    console.error('Error connecting to RabbitMQ:', error);
    process.exit(1);
  }
}

async function connectToDatabase() {
  try {
    connection = mysql.createConnection(dbConfig);
    await connection.connect();
    console.log('Connected to MySQL database');
  } catch (error) {
    console.error('Error connecting to MySQL database:', error);
    process.exit(1);
  }
}

function handleMessage(message) {
  const msgContent = JSON.parse(message.content.toString());
  const { type, payload } = msgContent;

  switch (type) {
    case 'INSERT':
      insertData(payload);
      break;
    case 'UPDATE':
      updateData(payload);
      break;
    case 'DELETE':
      deleteData(payload);
      break;
    default:
      console.log('Unknown message type:', type);
  }
}

function insertData(data) {
  const query = `INSERT INTO your_table (column1, column2) VALUES (?, ?)`;
  connection.query(query, [data.column1, data.column2], (error, results) => {
    if (error) {
      console.error('Error inserting data:', error);
    } else {
      console.log('Data inserted successfully');
    }
  });
}

function updateData(data) {
  const query = `UPDATE your_table SET column1 = ?, column2 = ? WHERE id = ?`;
  connection.query(query, [data.column1, data.column2, data.id], (error, results) => {
    if (error) {
      console.error('Error updating data:', error);
    } else {
      console.log('Data updated successfully');
    }
  });
}

function deleteData(data) {
  const query = `DELETE FROM your_table WHERE id = ?`;
  connection.query(query, [data.id], (error, results) => {
    if (error) {
      console.error('Error deleting data:', error);
    } else {
      console.log('Data deleted successfully');
    }
  });
}

async function startConsuming() {
  await connectToRabbitMQ();
  await connectToDatabase();

  channel.consume(queueName, (message) => {
    handleMessage(message);
    channel.ack(message);
  }, { noAck: false });

  console.log('Waiting for messages...');
}

startConsuming().catch(console.error);